 94→function truncateContent(content: string, maxLength: number): string {
 95→  const singleLine = content.replace(/\n/g, ' ');
 96→  if (singleLine.length <= maxLength) return singleLine;
 97→  return singleLine.slice(0, maxLength) + '\u2026';
 98→}
