106→function rowToEntry(row: SnippetRow): SnippetEntry {
107→  const parsed = new Date(row.created_at);
108→  const createdAt = isNaN(parsed.getTime()) ? new Date() : parsed;
109→
110→  let tags: SnippetEntry['tags'] = [];
111→  try {
112→    const raw = JSON.parse(row.tags);
113→    if (Array.isArray(raw)) {
114→      tags = raw.map((t: {
115→        text?: string;
116→        color?: string;
117→      }) => ({
118→        text: typeof t.text === 'string' ? t.text : '',
119→        color:
120→          typeof t.color === 'string' && isTagColor(t.color)
121→            ? t.color
122→            : undefined,
123→      }));
124→    }
125→  } catch {
126→    // empty
127→  }
128→
129→  return {
130→    id: row.id,
131→    name: row.name,
132→    keyword: row.keyword,
133→    content: row.content,
134→    category: isSnippetCategory(row.category) ? row.category : 'general',
135→    tags,
136→    createdAt,
137→  };
138→}
