201→function EditSnippetView({ snippet, onSubmit }: EditSnippetViewProps) {
202→  const [form, setForm] = useState<SnippetFormState>(() => {
203→    if (snippet) {
204→      return {
205→        name: snippet.name,
206→        keyword: snippet.keyword,
207→        snippet: snippet.content,
208→        category: snippet.category,
209→        tags: snippet.tags.map(t => t.text.toLowerCase()),
210→      };
211→    }
212→    return INITIAL_SNIPPET_FORM;
213→  });
214→  const [errors, setErrors] = useState<
215→    Partial<Record<keyof SnippetFormState, string>>
216→  >({});
217→
218→  const handleSubmit = useCallback(() => {
219→    const newErrors: Partial<Record<keyof SnippetFormState, string>> = {};
220→    if (!form.name.trim()) {
221→      newErrors.name = 'Name is required';
222→    }
223→    if (!form.snippet.trim()) {
224→      newErrors.snippet = 'Snippet content is required';
225→    }
226→    setErrors(newErrors);
227→    if (Object.keys(newErrors).length > 0) return;
228→    onSubmit(form);
229→  }, [
230→    form,
231→    onSubmit,
232→  ]);
233→
234→  useKeyboardShortcut(
235→    {
236→      key: 'Enter',
237→      meta: true,
238→    },
239→    handleSubmit,
240→  );
241→
242→  return (
243→    <Form onSubmit={handleSubmit}>
244→      <FormTextField
245→        label="Name"
246→        value={form.name}
247→        onChange={v =>
248→          setForm(prev => ({
249→            ...prev,
250→            name: v,
251→          }))
252→        }
253→        placeholder="e.g. Email Signature"
254→        error={errors.name}
255→        autoFocus
256→      />
257→      <FormTextField
258→        label="Keyword"
259→        value={form.keyword}
260→        onChange={v =>
261→          setForm(prev => ({
262→            ...prev,
263→            keyword: v,
264→          }))
265→        }
266→        placeholder="e.g. !sig"
267→        description="Type this to expand the snippet"
268→      />
269→      <FormDropdown
270→        label="Category"
271→        value={form.category}
272→        onChange={v => {
273→          if (isSnippetCategory(v)) {
274→            setForm(prev => ({
275→              ...prev,
276→              category: v,
277→            }));
278→          }
279→        }}
280→        options={FORM_CATEGORY_OPTIONS}
281→        placeholder="Select a category"
282→      />
283→      <FormTagPicker
284→        label="Tags"
285→        value={form.tags}
286→        onChange={v =>
287→          setForm(prev => ({
288→            ...prev,
289→            tags: v,
290→          }))
291→        }
292→        options={FORM_TAG_OPTIONS}
293→        placeholder="Add tags..."
294→        description="Categorize your snippet with tags"
295→      />
296→      <FormTextArea
297→        label="Snippet"
298→        value={form.snippet}
299→        onChange={v =>
300→          setForm(prev => ({
301→            ...prev,
302→            snippet: v,
303→          }))
304→        }
305→        placeholder="Enter your snippet content..."
306→        error={errors.snippet}
307→        rows={5}
308→      />
309→    </Form>
310→  );
311→}
